files.contents:
th,
td {
  border: 1px solid lightgray;
  padding: 8px;
}

tr:nth-child(even) {
  background-color: orangered;
}

tr:nth-child(odd) {
  background-color: lightgreen;
}

li:first-child {
  background-color: orangered;
}

li:last-child {
  background-color: lightgreen;
}

.container div:only-child {
  border: 2px solid crimson;
  padding: 10px;
  background-color: lightblue;
}

section p:first-of-type {
  background-color: lightgreen;
}

section p:last-of-type {
  background-color:lightblue;
}
